def expand_dataset() -> None:
    """Expand each of the 8 category JSON files in app/data/prompts/."""
    _PROMPTS_DIR.mkdir(parents=True, exist_ok=True)

    for category, new_prompts in _EXPANDED_PROMPTS.items():
        file_path = _PROMPTS_DIR / f"{category}.json"
        
        # 1. Read existing prompts if file exists, else initialize empty list
        existing_prompts = []
        if file_path.exists():
            try:
                with file_path.open("r", encoding="utf-8") as f:
                    existing_prompts = json.load(f)
            except Exception as e:
                print(f"Error reading {file_path.name}: {e}. Initializing fresh file.")
        
        # 2. Extract existing IDs to find next index
        existing_ids = {p.get("id") for p in existing_prompts if p.get("id")}
        print(f"Category '{category}': found {len(existing_prompts)} existing prompts.")

        # Ensure we only append prompts up to the target size
        # We want to add exactly 60 prompts. If we already have 20, total will be 80.
        appended_count = 0
        next_id_idx = len(existing_prompts) + 1
        
        for new_p in new_prompts:
            # Format custom ID: e.g. coding_021, coding_022
            p_id = f"{category}_{next_id_idx:03d}"
            
            # Skip if ID already exists (in case script runs multiple times)
            if p_id in existing_ids:
                next_id_idx += 1
                continue
                
            entry = {
                "id": p_id,
                "category": category,
                "difficulty": new_p["difficulty"],
                "expected_reasoning": new_p["expected_reasoning"],
                "prompt": new_p["prompt"]
            }
            existing_prompts.append(entry)
            next_id_idx += 1
            appended_count += 1
            
        # 3. Write back to disk
        with file_path.open("w", encoding="utf-8") as f:
            json.dump(existing_prompts, f, indent=2, ensure_ascii=False)
            f.write("\n")
            
        print(f"  -> Appended {appended_count} prompts. New total for '{category}': {len(existing_prompts)}.")

    print("\nPrompts expansion complete! Total prompts across all categories is now 640.")


if __name__ == "__main__":
    expand_dataset()
